154	// For a GLOBAL (non-link-local) v6 source, fe80::/10 link-local addresses are
155	// EXCLUDED from the count: an up interface virtually always carries a kernel
156	// link-local alongside its configured global v6 address, but the kernel never
157	// source-selects a link-local for a global destination, so a link-local co-resident
158	// does not void the global source_addr pin — a wildcard+device socket still sources
159	// only from the configured global address (defect D13). For a v4 source or a
160	// link-local v6 source every same-family address is counted, unchanged: a
161	// link-local-only interface, and any v4 interface, is unaffected.
162	func familyBindCount(want netip.Addr, addrs []netip.Addr) (familyCount int, owns bool) {
163		excludeLinkLocal := !want.Is4() && !want.IsLinkLocalUnicast()
